   218	func selectComparisonTarget(history []HistoryRecord, against string) (HistoryRecord, error) {
   219		switch against {
   220		case "", "latest":
   221			return history[len(history)-1], nil
   222		case "baseline":
   223			return history[0], nil
   224		default:
   225			for _, rec := range history {
   226				if rec.RunID == against {
   227					return rec, nil
   228				}
   229			}
   230			return HistoryRecord{}, fmt.Errorf("comparison target %q not found", against)
   231		}
   232	}
